#!/usr/bin/env node
/* Generated by Lantern */
const lamplighter = require("../../../src/lamplighter");
lamplighter.bootstrapBuiltins();

lamplighter.defineType("game", null, {"author":"string","version":"int"});

const game = lamplighter.type("game");

lamplighter.createObject("game", "Extended", { "author": "Test Author", "version": 1 });

lamplighter.onEvent("startup", () => {
    let this_game = game.all.first;
    lamplighter.print(this_game.name);
    lamplighter.print("by " + this_game.author);
    lamplighter.print("version " + this_game.version);
});
lamplighter.onEvent("startup", () => {
    let this_game = game.all.first;
    this_game.version = this_game.version + 1;
    lamplighter.print("after " + this_game.version);
});
lamplighter.onEvent("validation", () => {
    lamplighter.error("invalid state");
});

lamplighter.run();
